<template>
  <div class="add-address">
    <van-nav-bar
      title="添加地址"
      left-text="返回"
      left-arrow
      @click-left="$router.push('/order/list')"
    />
    <van-address-edit
      :address-info="info"
      :area-list="areaList"
      show-postal
      show-set-default
      :area-columns-placeholder="['请选择', '请选择', '请选择']"
      @save="onSave"
    >
    </van-address-edit>
  </div>
</template>

<script>
import { areaList } from "@vant/area-data";
import $axios from "@/utils/index";
export default {
  data() {
    return {
      areaList: areaList,
      info: {
        name: "哈哈",
        tel: "13800000000",
        country: "中国",
        province: "广西壮族自治区",
        city: "南宁市",
        county: "青秀区",
        addressDetail: "青秀山",
        areaCode: "450105",
        postalCode: "530000",
        isDefault: true,
      },
    };
  },
  methods: {
    async onSave(content) {
        // console.log(content)
      try {
        let res = await $axios.post("address/add", content);
        this.$router.push('/address')
      } catch (err) {
          console.log(err)
      }
    },
    
  },
};
</script>

